import{_ as h,C as e,o as c,c as l,E as a,a2 as s,w as r,a as d}from"./chunks/framework.C24VBsJ9.js";const q=JSON.parse('{"title":"内核核心功能","description":"","frontmatter":{"title":"内核核心功能"},"headers":[],"relativePath":"tutorial/kernel/core-functional/index.md","filePath":"tutorial/kernel/core-functional/index.md","lastUpdated":1781501753000}'),_={name:"tutorial/kernel/core-functional/index.md"};function p(b,t,f,u,m,k){const o=e("PageHeader"),i=e("ChapterLink"),n=e("ChapterNav");return c(),l("div",null,[a(o,{icon:"⚙️",title:"内核核心功能",description:"并发同步、中断、阻塞/非阻塞 I/O —— 编写健壮驱动绕不开的内核机制"}),t[2]||(t[2]=s('<h2 id="为什么单独成组" tabindex="-1">为什么单独成组？ <a class="header-anchor" href="#为什么单独成组" aria-label="Permalink to &quot;为什么单独成组？&quot;">​</a></h2><p>并发与同步是 Linux 内核里最容易踩坑、也最难调试的部分。一段在单核、不开抢占时永远正确的代码，换到 i.MX6ULL 的双核 Cortex-A7 + SMP + 抢占环境下，就可能因为时序的细微差异而偶发崩溃——这类「幽灵 Bug」往往调一整天都复现不了。</p><p>这一组教程把驱动开发真正用得上的内核机制集中讲透：从并发的来源与同步原语，到中断上下文，再到字符设备的三种 I/O 模型。学完之后，你会清楚什么场景该用自旋锁、什么场景该用信号量，以及为什么同一个 <code>read</code> 既可以阻塞、也可以立即返回、还能用信号通知。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>掌握内核里的并发来源与同步原语（原子操作 / 自旋锁 / 互斥锁 / 信号量），理解中断上下文与处理流程，能用阻塞、非阻塞、异步通知三种模型编写字符设备驱动。</p></div><div class="info custom-block"><p class="custom-block-title">前置知识</p><p>内核模块机制（<a href="./../../driver/modules/">modules/</a>）· 字符设备基础（<a href="./../../driver/00_chardev_base/">字符设备教程</a>）· C 语言高级特性</p></div><h2 id="教程目录" tabindex="-1">教程目录 <a class="header-anchor" href="#教程目录" aria-label="Permalink to &quot;教程目录&quot;">​</a></h2><h3 id="并发与同步" tabindex="-1">并发与同步 <a class="header-anchor" href="#并发与同步" aria-label="Permalink to &quot;并发与同步&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>标题</th><th>说明</th></tr></thead><tbody><tr><td><a href="./01_concurrency_basics">01_concurrency_basics</a></td><td>并发基础</td><td>并发的四大来源、单核 vs 多核、为什么需要同步</td></tr><tr><td><a href="./02_atomic_operations">02_atomic_operations</a></td><td>原子操作</td><td>原子变量、内存屏障、典型用法</td></tr><tr><td><a href="./03_spinlocks">03_spinlocks</a></td><td>自旋锁</td><td>spinlock 原理、读写自旋锁、使用约束</td></tr><tr><td><a href="./04_mutex_semaphore">04_mutex_semaphore</a></td><td>互斥锁与信号量</td><td>mutex 与 semaphore 的区别与选型</td></tr></tbody></table><h3 id="时间与定时器" tabindex="-1">时间与定时器 <a class="header-anchor" href="#时间与定时器" aria-label="Permalink to &quot;时间与定时器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>标题</th><th>说明</th></tr></thead><tbody><tr><td><a href="./05_time_management">05_time_management</a></td><td>时间管理</td><td>jiffies、ktime、时间测量与延时</td></tr><tr><td><a href="./06_timer_practice">06_timer_practice</a></td><td>定时器实践</td><td>内核定时器、高精度定时器实战</td></tr></tbody></table><h3 id="中断" tabindex="-1">中断 <a class="header-anchor" href="#中断" aria-label="Permalink to &quot;中断&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>标题</th><th>说明</th></tr></thead><tbody><tr><td><a href="./07_interrupt_basics">07_interrupt_basics</a></td><td>中断基础</td><td>中断上下文、上半部 / 下半部机制</td></tr><tr><td><a href="./08_interrupt_practice">08_interrupt_practice</a></td><td>中断实践</td><td>注册与处理中断、顶半部与底半部协作</td></tr></tbody></table><h3 id="i-o-模型" tabindex="-1">I/O 模型 <a class="header-anchor" href="#i-o-模型" aria-label="Permalink to &quot;I/O 模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>标题</th><th>说明</th></tr></thead><tbody><tr><td><a href="./09_blocking_io">09_blocking_io</a></td><td>阻塞 I/O</td><td>等待队列、阻塞式 read 实现</td></tr><tr><td><a href="./10_nonblocking_io">10_nonblocking_io</a></td><td>非阻塞 I/O</td><td>O_NONBLOCK、poll / select 轮询机制</td></tr><tr><td><a href="./11_async_notification">11_async_notification</a></td><td>异步通知</td><td>fasync 机制、SIGIO 信号通知用户空间</td></tr></tbody></table><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><ol><li>从 <a href="./01_concurrency_basics">01 并发基础</a> 建立对「并发」的全局认知</li><li>用 <a href="./02_atomic_operations">02 原子操作</a>、<a href="./03_spinlocks">03 自旋锁</a>、<a href="./04_mutex_semaphore">04 互斥锁与信号量</a> 逐层掌握同步原语</li><li>学习 <a href="./05_time_management">05 时间管理</a> 与 <a href="./06_timer_practice">06 定时器实践</a></li><li>攻克 <a href="./07_interrupt_basics">07 中断基础</a> 与 <a href="./08_interrupt_practice">08 中断实践</a></li><li>最后用 <a href="./09_blocking_io">09 阻塞 I/O</a>、<a href="./10_nonblocking_io">10 非阻塞 I/O</a>、<a href="./11_async_notification">11 异步通知</a> 理解三种 I/O 模型</li></ol><h2 id="继续学习" tabindex="-1">继续学习 <a class="header-anchor" href="#继续学习" aria-label="Permalink to &quot;继续学习&quot;">​</a></h2>',17)),a(n,{variant:"sub"},{default:r(()=>[a(i,{href:"01_concurrency_basics",variant:"sub"},{default:r(()=>[...t[0]||(t[0]=[d("从并发基础开始 →",-1)])]),_:1}),a(i,{href:"../",variant:"sub"},{default:r(()=>[...t[1]||(t[1]=[d("← 返回内核教程",-1)])]),_:1})]),_:1})])}const v=h(_,[["render",p]]);export{q as __pageData,v as default};
